import logging
from typing import Optional, Dict, Any
from enum import Enum
from datetime import datetime, timedelta

class ErrorSeverity(Enum):
    TRANSIENT = 1  # Temporary, retry-able
    RECOVERABLE = 2  # Can roll back and resume
    TERMINAL = 3  # Agent must halt

class CricketAgentRecoveryEngine:
    def __init__(self, max_recovery_attempts=3, checkpoint_interval=5):
        self.max_recovery_attempts = max_recovery_attempts
        self.checkpoint_interval = checkpoint_interval
        self.state_stack = []  # Stack of execution states
        self.memory_buffer = {}  # Agent's episodic memory
        self.error_log = []  # Timestamped error history
        self.batting_performance = {}  # Tracks batter decision outcomes
        self.logger = logging.getLogger("CricketAgent")

    def checkpoint_state(self, current_batter: str, action: str, context: Dict[str, Any]):
        """Save execution checkpoint before risky action."""
        checkpoint = {
            "timestamp": datetime.now(),
            "batter": current_batter,
            "last_action": action,
            "context": context.copy(),
            "memory_snapshot": self.memory_buffer.copy()
        }
        self.state_stack.append(checkpoint)
        if len(self.state_stack) > self.checkpoint_interval:
            self.state_stack.pop(0)  # Maintain bounded history

    def execute_batting_action(self, batter: str, bowler: str, pitch_type: str) -> bool:
        """Execute agent action with error handling."""
        recovery_attempt = 0
        last_error = None

        while recovery_attempt < self.max_recovery_attempts:
            try:
                # Simulate tool invocation (batting action against bowler)
                if pitch_type == "yorker" and bowler == "Jasprit_Bumrah":
                    # High-failure scenario
                    if recovery_attempt == 0:
                        raise RuntimeError(f"Bowled! {batter} failed to negotiate yorker.")

                # Action succeeded
                self.batting_performance[batter] = {"status": "success", "bowler": bowler}
                self.logger.info(f"✓ {batter} successfully played against {bowler}'s {pitch_type}")
                return True

            except RuntimeError as e:
                last_error = e
                error_severity = self._classify_error(str(e))
                self._log_error(batter, str(e), error_severity)
                recovery_attempt += 1

                if error_severity == ErrorSeverity.TERMINAL:
                    self.logger.error(f"Terminal error. {batter} is out.")
                    return False

                # Transient recovery: check memory and adjust strategy
                prior_against_bowler = self.memory_buffer.get(bowler, {})
                if prior_against_bowler.get("success_rate", 0) < 0.3:
                    self.logger.warning(f"Low success rate against {bowler}. Triggering defensive strategy.")
                    pitch_type = "dot_ball"  # Fallback to safer action
                else:
                    self.logger.info(f"Retrying with adjusted technique (attempt {recovery_attempt}).")

                # Roll back to last checkpoint if available
                if self.state_stack:
                    rollback_point = self.state_stack[-1]
                    self.memory_buffer = rollback_point["memory_snapshot"]
                    self.logger.info(f"Rolled back to checkpoint at {rollback_point['timestamp']}")

        self.logger.error(f"Max recovery attempts exceeded for {batter}. Final error: {last_error}")
        return False

    def _classify_error(self, error_msg: str) -> ErrorSeverity:
        """Classify error severity based on message patterns."""
        if "Bowled" in error_msg or "LBW" in error_msg:
            return ErrorSeverity.TERMINAL
        elif "network" in error_msg.lower():
            return ErrorSeverity.TRANSIENT
        else:
            return ErrorSeverity.RECOVERABLE

    def _log_error(self, batter: str, error_msg: str, severity: ErrorSeverity):
        """Log error with timestamp and context."""
        self.error_log.append({
            "timestamp": datetime.now(),
            "batter": batter,
            "error": error_msg,
            "severity": severity.name
        })
        self.logger.warning(f"[{severity.name}] {batter}: {error_msg}")

    def update_memory_from_outcome(self, bowler: str, outcome: Dict[str, Any]):
        """Learn from experience to improve future recovery decisions."""
        if bowler not in self.memory_buffer:
            self.memory_buffer[bowler] = {"attempts": 0, "successes": 0}

        self.memory_buffer[bowler]["attempts"] += 1
        if outcome.get("success"):
            self.memory_buffer[bowler]["successes"] += 1

        self.memory_buffer[bowler]["success_rate"] = (
            self.memory_buffer[bowler]["successes"] / self.memory_buffer[bowler]["attempts"]
        )

# Example usage
agent = CricketAgentRecoveryEngine(max_recovery_attempts=3)

# Rohit Sharma facing Jasprit Bumrah's yorker
agent.checkpoint_state("Rohit_Sharma", "aggressive_drive", {"runs_needed": 45, "balls_left": 8})
success = agent.execute_batting_action("Rohit_Sharma", "Jasprit_Bumrah", "yorker")

# Learn from outcome
agent.update_memory_from_outcome("Jasprit_Bumrah", {"success": success})

# View error log
for err in agent.error_log:
    print(f"[{err['severity']}] {err['timestamp']}: {err['batter']} - {err['error']}")

