import asyncio
import logging
from enum import Enum

class ShotAction(Enum):
    AGGRESSIVE_DRIVE = "drive"
    DEFENSIVE_BLOCK = "block"
    LEAVE = "leave"

class ResilientBattingAgent:
    def __init__(self, max_retries=3, base_delay=0.5):
        self.max_retries = max_retries
        self.base_delay = base_delay
        self.logger = logging.getLogger("batting_agent")
        self.last_checkpoint = {"inning_state": None, "balls_faced": 0}

    async def select_shot(self, ball_delivery, retry_count=0):
        try:
            # Primary tool: high-confidence analysis
            trajectory = await self.analyze_delivery_primary(ball_delivery)
            shot = self.execute_shot(trajectory)
            self.logger.info(f"Shot selected: {shot.value}")
            return shot

        except TimeoutError as e:
            # Transient: retry with exponential backoff
            if retry_count < self.max_retries:
                delay = self.base_delay * (2 ** retry_count)
                self.logger.warning(f"Delivery analysis timeout. Retrying in {delay}s (attempt {retry_count + 1})")
                await asyncio.sleep(delay)
                return await self.select_shot(ball_delivery, retry_count + 1)
            else:
                self.logger.error(f"Max retries exceeded for delivery {ball_delivery.id}")
                # Fallback chain
                return await self.fallback_shot_selection(ball_delivery)

        except ValueError as e:
            # Invalid delivery data: use fallback immediately (not retryable)
            self.logger.warning(f"Invalid delivery data: {e}. Using fallback strategy.")
            return await self.fallback_shot_selection(ball_delivery)

        except Exception as e:
            # Critical error: rollback to checkpoint
            self.logger.critical(f"Critical agent failure: {e}. Rolling back to checkpoint.")
            self.restore_checkpoint()
            return ShotAction.LEAVE  # Safe default after rollback

    async def fallback_shot_selection(self, ball_delivery):
        """Fallback chain: secondary analysis methods"""
        fallbacks = [
            self.analyze_delivery_secondary,  # Slower but more robust
            self.rule_based_shot_selection,   # Deterministic heuristic
        ]

        for fallback_method in fallbacks:
            try:
                result = await fallback_method(ball_delivery)
                self.logger.info(f"Fallback succeeded via {fallback_method.__name__}")
                return result
            except Exception as e:
                self.logger.warning(f"Fallback {fallback_method.__name__} failed: {e}. Trying next.")
                continue

        # Ultimate fallback: safe conservative action
        self.logger.error("All fallbacks exhausted. Defaulting to LEAVE.")
        return ShotAction.LEAVE

    def save_checkpoint(self, inning_state, balls_faced):
        """Save agent state before risky decisions"""
        self.last_checkpoint = {"inning_state": inning_state, "balls_faced": balls_faced}
        self.logger.debug(f"Checkpoint saved: balls_faced={balls_faced}")

    def restore_checkpoint(self):
        """Rollback to last valid state"""
        self.logger.info(f"Restoring checkpoint: {self.last_checkpoint}")
        # Restore agent state from checkpoint
        pass

    async def analyze_delivery_primary(self, ball_delivery):
        """Primary tool (fast, less reliable)"""
        await asyncio.sleep(0.1)
        if ball_delivery.quality < 0.3:
            raise ValueError(f"Poor quality delivery data: {ball_delivery.quality}")
        return {"line": ball_delivery.line, "length": ball_delivery.length}

    async def analyze_delivery_secondary(self, ball_delivery):
        """Secondary tool (slower, more reliable)"""
        await asyncio.sleep(0.5)  # More thorough analysis
        return {"line": ball_delivery.line, "length": ball_delivery.length}

    async def rule_based_shot_selection(self, ball_delivery):
        """Deterministic heuristic (no external tools)"""
        if ball_delivery.line == "off_stump":
            return ShotAction.DEFENSIVE_BLOCK
        elif ball_delivery.line == "leg_stump":
            return ShotAction.AGGRESSIVE_DRIVE
        return ShotAction.LEAVE

    def execute_shot(self, trajectory):
        return ShotAction.DEFENSIVE_BLOCK if trajectory["length"] == "short" else ShotAction.AGGRESSIVE_DRIVE

import logging
from enum import Enum
from datetime import datetime, timedelta
from typing import Optional, Callable, Any

class RecoveryStrategy(Enum):
    RETRY = "retry"
    FALLBACK = "fallback"
    ESCALATE = "escalate"
    ABORT = "abort"

class CricketAgentRecovery:
    """Error handling for cricket match prediction agent."""

    def __init__(self, max_retries: int = 3, base_backoff: int = 2):
        self.max_retries = max_retries
        self.base_backoff = base_backoff
        self.logger = logging.getLogger(__name__)
        self.state_checkpoints = {}

    def save_checkpoint(self, agent_id: str, state: dict) -> None:
        """Save agent state before risky operations."""
        self.state_checkpoints[agent_id] = {
            'state': state,
            'timestamp': datetime.now()
        }
        self.logger.info(f"Checkpoint saved for {agent_id}")

    def restore_checkpoint(self, agent_id: str) -> Optional[dict]:
        """Restore agent to last known good state."""
        if agent_id in self.state_checkpoints:
            return self.state_checkpoints[agent_id]['state']
        return None

    def execute_with_recovery(
        self,
        agent_id: str,
        action: Callable,
        strategy: RecoveryStrategy = RecoveryStrategy.RETRY,
        fallback_action: Optional[Callable] = None
    ) -> Any:
        """Execute agent action with recovery strategy."""

        for attempt in range(self.max_retries):
            try:
                result = action()
                self.logger.info(f"Action succeeded on attempt {attempt + 1}")
                return result

            except Exception as e:
                self.logger.error(f"Attempt {attempt + 1} failed: {str(e)}")

                if strategy == RecoveryStrategy.RETRY:
                    if attempt < self.max_retries - 1:
                        wait_time = self.base_backoff ** attempt
                        self.logger.info(f"Retrying in {wait_time}s...")
                        # In real code: time.sleep(wait_time)
                    else:
                        self.logger.error("Max retries exceeded, attempting fallback")
                        if fallback_action:
                            return self._execute_fallback(fallback_action, agent_id)

                elif strategy == RecoveryStrategy.FALLBACK:
                    if fallback_action:
                        return self._execute_fallback(fallback_action, agent_id)

                elif strategy == RecoveryStrategy.ESCALATE:
                    return self._escalate_to_human(agent_id, str(e))

                elif strategy == RecoveryStrategy.ABORT:
                    self.logger.critical(f"Aborting agent {agent_id}")
                    raise

        return None

    def _execute_fallback(self, fallback_action: Callable, agent_id: str) -> Any:
        """Execute fallback action after primary failure."""
        try:
            self.logger.info(f"Executing fallback for {agent_id}")
            return fallback_action()
        except Exception as e:
            self.logger.error(f"Fallback failed: {str(e)}")
            return self._escalate_to_human(agent_id, f"Fallback error: {str(e)}")

    def _escalate_to_human(self, agent_id: str, error_msg: str) -> dict:
        """Escalate unrecoverable errors to human operators."""
        self.logger.warning(f"Escalating {agent_id} to human: {error_msg}")
        return {
            'status': 'escalated',
            'agent_id': agent_id,
            'error': error_msg,
            'timestamp': datetime.now().isoformat(),
            'last_checkpoint': self.restore_checkpoint(agent_id)
        }

# Example usage
recovery_handler = CricketAgentRecovery(max_retries=3)

def fetch_player_stats():
    """Primary action: fetch live player statistics."""
    # Simulate API call that might fail
    raise ConnectionError("Stats API timeout")

def cached_player_stats():
    """Fallback: use cached statistics from 1 hour ago."""
    return {'source': 'cache', 'timestamp': 'cached_1h_ago'}

# Execute with automatic recovery
result = recovery_handler.execute_with_recovery(
    agent_id="cricket_predictor_001",
    action=fetch_player_stats,
    strategy=RecoveryStrategy.RETRY,
    fallback_action=cached_player_stats
)
